sql:
SELECT patents_registered 
FROM innovation_indicators 
WHERE country_code = '1';

SELECT program_name, description, start_date, budget
FROM government_programs
WHERE country_code = 'AUS';

SELECT AVG(ei.government_support) AS average_government_support
FROM entrepreneurial_indicators ei
WHERE ei.global_competitiveness > 70;

external_knowledge:
- The indicators are averages of various factors influencing entrepreneurship; 
- A higher score indicates a more favorable environment for entrepreneurship; 
- The scores are calculated at the country level.

sql:
SELECT global_competitiveness
FROM entrepreneurial_indicators
WHERE global_competitiveness > 70;

SELECT institution_name
FROM educational_institutions
WHERE curriculum_quality > 3.5;

SELECT country_code
FROM taxation
WHERE corporate_tax_rate = (SELECT MAX(corporate_tax_rate) FROM taxation);
